SELECT a.id as id , a.site_code as siteCode, a.apply_time as applyTime, a.first_review_time as firstReviewTime , a.review_order_number as reviewOrderNumber, a.review_status as reviewOperation, a.review_status as reviewStatus, a.apply_user as applyUser, a.first_reviewer as firstReviewer, a.lock_status as lockStatus, a.adjust_type as adjustType, a.adjust_amount as adjustAmount, a.locker as locker, a.review_remark as reviewRemark, a.created_time as createdTime, a.updated_time as updatedTime, a.creator as creator, a.updater as updater, a.currency as currency, a.remark as remark, b.account_status as accountStatus, a.site_name as siteName FROM site_security_adjust_review a LEFT JOIN site_security_balance b ON a.site_code = b.site_code
a.review_status in (1,2)
AND a.apply_time >= #{vo.applyTimeStart}
AND a.apply_time <= #{vo.applyTimeEnd}
AND a.first_review_time >= #{vo.firstReviewTimeStart}
AND a.first_review_time <= #{vo.firstReviewTimeEnd}
AND a.review_order_number = #{vo.reviewOrderNumber}
AND a.lock_status = #{vo.lockStatus}
AND a.site_name = #{vo.siteName}
AND a.adjust_type = #{vo.adjustType}
AND a.first_reviewer = #{vo.firstReviewer}
ORDER BY lock_status desc,a.review_operation ASC, a.review_status ASC, a.apply_time desc

SELECT a.id as id, a.site_code as siteCode, a.site_name as siteName, a.review_order_number as reviewOrderNumber, a.review_status as reviewStatus, a.adjust_type as adjustType, a.currency as currency , a.apply_user as applyUser, a.remark as remark, a.adjust_amount as adjustAmount, a.apply_time as applyTime, a.first_reviewer as firstReviewer, a.first_review_time as firstReviewTime, ( a.first_review_time - a.lock_time )/ 1000 AS reviewTotalTime, b.account_status as accountStatus, b.security_status as securityStatus, a.review_remark as reviewRemark FROM site_security_adjust_review a LEFT JOIN site_security_balance b ON a.site_code = b.site_code
a.review_status in (3,4)
AND a.apply_time >= #{vo.applyTimeStart}
AND a.apply_time <= #{vo.applyTimeEnd}
AND a.first_review_time >= #{vo.firstReviewTimeStart}
AND a.first_review_time <= #{vo.firstReviewTimeEnd}
AND a.review_order_number = #{vo.reviewOrderNumber}
AND a.site_name = #{vo.siteName}
AND a.adjust_type = #{vo.adjustType}
AND a.first_reviewer = #{vo.firstReviewer}
AND a.review_status = #{vo.reviewStatus}
ORDER BY a.updated_time desc

